// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! Copies of the component GUMBO contracts for system-level verification.
//! The originals live in the component crates, which this crate cannot
//! depend on (they are staticlibs); both are generated from the same
//! GUMBO source, so they are identical by construction (TCB item T3).

#![allow(non_snake_case)]

use data::*;
use vstd::prelude::*;

verus! {

// -- TempControlSystem_Instance.tsp.tst --
pub mod sensor {
  use super::*;

  /** initialize guarantee initializes
    */
  pub open spec fn initialize_initializes(
    api_currentTemp: Option<TempControl_SysVerif::Temperature>) -> bool
  {
    api_currentTemp.unwrap().degrees == 72i32
  }

  /** integration guarantee Sensor_Temperature_Range (I-Guar, outgoing port currentTemp)
    */
  pub open spec fn integration_spec_Sensor_Temperature_Range_guarantee(
    api_currentTemp: Option<TempControl_SysVerif::Temperature>) -> bool
  {
    (api_currentTemp.is_some()) ==> ((api_currentTemp.unwrap().degrees >= -40i32) &&
      (api_currentTemp.unwrap().degrees <= 122i32))
  }
}

// -- TempControlSystem_Instance.tcp.tct --
pub mod control {
  use super::*;

  /** initialize guarantee defaultSetPoint
    */
  pub open spec fn initialize_defaultSetPoint(
    currentSetPoint: TempControl_SysVerif::SetPoint) -> bool
  {
    (currentSetPoint.low.degrees == 70i32) &&
      (currentSetPoint.high.degrees == 90i32)
  }

  /** initialize guarantee defaultFanStates
    */
  pub open spec fn initialize_defaultFanStates(
    currentFanState: TempControl_SysVerif::FanCmd) -> bool
  {
    currentFanState == TempControl_SysVerif::FanCmd::Off
  }

  /** initialize guarantee defaultLatestTemp
    */
  pub open spec fn initialize_defaultLatestTemp(
    latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    latestTemp.degrees == 72i32
  }

  /** compute assume a1
    *   If the previously received currentTemp was less than the previously
    *   received setPoint then the last fan command must have been Off
    */
  pub open spec fn compute_spec_a1_assume(
    In_currentFanState: TempControl_SysVerif::FanCmd,
    In_currentSetPoint: TempControl_SysVerif::SetPoint,
    In_fanError: bool,
    In_latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    (!In_fanError &&
      (In_latestTemp.degrees < In_currentSetPoint.low.degrees)) ==>
      (In_currentFanState == TempControl_SysVerif::FanCmd::Off)
  }

  /** compute assume a2
    *   If the previously received currentTemp was more than the previously
    *   received setPoint then the last fan command must have been On
    */
  pub open spec fn compute_spec_a2_assume(
    In_currentFanState: TempControl_SysVerif::FanCmd,
    In_currentSetPoint: TempControl_SysVerif::SetPoint,
    In_fanError: bool,
    In_latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    (!In_fanError &&
      (In_latestTemp.degrees > In_currentSetPoint.high.degrees)) ==>
      (In_currentFanState == TempControl_SysVerif::FanCmd::On)
  }

  /** compute guarantee errorState
    *   If the fan sent FanAck.Error then continue sending the
    *   last fan command until the fan sends FanAck.Ok
    */
  pub open spec fn compute_spec_errorState_guarantee(
    In_currentFanState: TempControl_SysVerif::FanCmd,
    currentFanState: TempControl_SysVerif::FanCmd,
    fanError: bool,
    api_fanCmd: Option<TempControl_SysVerif::FanCmd>) -> bool
  {
    fanError ==>
      ((In_currentFanState == currentFanState) &&
        (api_fanCmd.is_some() &&
          (api_fanCmd.unwrap() == currentFanState)))
  }

  /** compute guarantee TC_Req_01
    *   If the current temperature is less than the set point, then the fan state shall be Off.
    */
  pub open spec fn compute_spec_TC_Req_01_guarantee(
    currentFanState: TempControl_SysVerif::FanCmd,
    currentSetPoint: TempControl_SysVerif::SetPoint,
    fanError: bool,
    latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    (!fanError &&
      (latestTemp.degrees < currentSetPoint.low.degrees)) ==>
      (currentFanState == TempControl_SysVerif::FanCmd::Off)
  }

  /** compute guarantee TC_Req_02
    *   If the current temperature is greater than the set point,
    *   then the fan state shall be On.
    */
  pub open spec fn compute_spec_TC_Req_02_guarantee(
    currentFanState: TempControl_SysVerif::FanCmd,
    currentSetPoint: TempControl_SysVerif::SetPoint,
    fanError: bool,
    latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    (!fanError &&
      (latestTemp.degrees > currentSetPoint.high.degrees)) ==>
      (currentFanState == TempControl_SysVerif::FanCmd::On)
  }

  /** compute guarantee TC_Req_03
    *   If the current temperature is greater than or equal to the
    *   current low set point and less than or equal to the current high set point,
    *   then the current fan state is maintained.
    */
  pub open spec fn compute_spec_TC_Req_03_guarantee(
    In_currentFanState: TempControl_SysVerif::FanCmd,
    currentFanState: TempControl_SysVerif::FanCmd,
    currentSetPoint: TempControl_SysVerif::SetPoint,
    fanError: bool,
    latestTemp: TempControl_SysVerif::Temperature) -> bool
  {
    ((!fanError &&
      (latestTemp.degrees >= currentSetPoint.low.degrees)) &&
      (latestTemp.degrees <= currentSetPoint.high.degrees)) ==>
      (currentFanState == In_currentFanState)
  }

  /** compute guarantee mustSendFanCmd
    *   If the local record of the fan state was updated,
    *   then send a fan command event with this updated value.
    */
  pub open spec fn compute_spec_mustSendFanCmd_guarantee(
    In_currentFanState: TempControl_SysVerif::FanCmd,
    currentFanState: TempControl_SysVerif::FanCmd,
    fanError: bool,
    api_fanCmd: Option<TempControl_SysVerif::FanCmd>) -> bool
  {
    ((!fanError &&
      (In_currentFanState != currentFanState)) ==>
      api_fanCmd.is_some() &&
        (api_fanCmd.unwrap() == currentFanState)) &&
      ((!fanError &&
        (currentFanState == In_currentFanState)) ==>
        api_fanCmd.is_none())
  }

  /** compute guarantee setPointChanged
    */
  pub open spec fn compute_spec_setPointChanged_guarantee(
    currentSetPoint: TempControl_SysVerif::SetPoint,
    api_setPoint: Option<TempControl_SysVerif::SetPoint>) -> bool
  {
    api_setPoint.is_some() ==>
      (currentSetPoint == api_setPoint.unwrap())
  }

  /** compute guarantee fanAck_setPointNotModified
    */
  pub open spec fn compute_spec_fanAck_setPointNotModified_guarantee(
    In_currentSetPoint: TempControl_SysVerif::SetPoint,
    currentSetPoint: TempControl_SysVerif::SetPoint,
    api_fanAck: Option<TempControl_SysVerif::FanAck>,
    api_setPoint: Option<TempControl_SysVerif::SetPoint>) -> bool
  {
    (api_fanAck.is_some() && !(api_setPoint.is_some())) ==>
      (currentSetPoint == In_currentSetPoint)
  }

  /** compute guarantee currentTemp_setPointNotModified
    */
  pub open spec fn compute_spec_currentTemp_setPointNotModified_guarantee(
    In_currentSetPoint: TempControl_SysVerif::SetPoint,
    currentSetPoint: TempControl_SysVerif::SetPoint,
    api_currentTemp: Option<TempControl_SysVerif::Temperature>,
    api_setPoint: Option<TempControl_SysVerif::SetPoint>) -> bool
  {
    (api_currentTemp.is_some() && !(api_setPoint.is_some())) ==>
      (currentSetPoint == In_currentSetPoint)
  }

  /** compute guarantee tempChanged
    */
  pub open spec fn compute_spec_tempChanged_guarantee(
    latestTemp: TempControl_SysVerif::Temperature,
    api_currentTemp: Option<TempControl_SysVerif::Temperature>) -> bool
  {
    api_currentTemp.is_some() ==>
      (latestTemp == api_currentTemp.unwrap())
  }

  /** compute guarantee setPoint_latestTempNotModified
    */
  pub open spec fn compute_spec_setPoint_latestTempNotModified_guarantee(
    In_latestTemp: TempControl_SysVerif::Temperature,
    latestTemp: TempControl_SysVerif::Temperature,
    api_currentTemp: Option<TempControl_SysVerif::Temperature>,
    api_setPoint: Option<TempControl_SysVerif::SetPoint>) -> bool
  {
    (api_setPoint.is_some() && !(api_currentTemp.is_some())) ==>
      (latestTemp == In_latestTemp)
  }

  /** compute guarantee fanAck_latestTempNotModified
    */
  pub open spec fn compute_spec_fanAck_latestTempNotModified_guarantee(
    In_latestTemp: TempControl_SysVerif::Temperature,
    latestTemp: TempControl_SysVerif::Temperature,
    api_currentTemp: Option<TempControl_SysVerif::Temperature>,
    api_fanAck: Option<TempControl_SysVerif::FanAck>) -> bool
  {
    (api_fanAck.is_some() && !(api_currentTemp.is_some())) ==>
      (latestTemp == In_latestTemp)
  }

  /** compute guarantee manageErrorState
    */
  pub open spec fn compute_spec_manageErrorState_guarantee(
    fanError: bool,
    api_fanAck: Option<TempControl_SysVerif::FanAck>) -> bool
  {
    api_fanAck.is_some() ==>
      (((api_fanAck.unwrap() == TempControl_SysVerif::FanAck::Ok) ==>
        !fanError) &&
        ((api_fanAck.unwrap() == TempControl_SysVerif::FanAck::Error) ==>
          fanError))
  }

  /** integration assume currentTempRange (I-Assm, incoming port currentTemp)
    */
  pub open spec fn integration_spec_currentTempRange_assume(
    api_currentTemp: Option<TempControl_SysVerif::Temperature>) -> bool
  {
    (api_currentTemp.is_some()) ==> ((api_currentTemp.unwrap().degrees >= -129i32) &&
      (api_currentTemp.unwrap().degrees <= 134i32))
  }
}

} // verus!
